const teamIds = new Set();

// Wir gehen durch das Array von n8n (meistens ein Item, das "items" enthält)
$input.all().forEach(item => {
  const matches = item.json.items || [];

  matches.forEach(m => {
    if (m.teamHomeId) teamIds.add(m.teamHomeId);
    if (m.teamAwayId) teamIds.add(m.teamAwayId);
  });
});

// Umwandlung in eine Liste für die API-Sports Squad Abfrage
return Array.from(teamIds).map(id => ({
  json: {
    teamId: id
  }
}));

const items = $input.all();
const results = [];

const positionMap = {
  "Defender":   "Defender",
  "Goalkeeper": "Goalkeeper",
  "Midfielder": "Midfielder",
  "Attacker":   "Forward",
};

const ALLOWED_LEAGUES = new Set([78, 2, 81]);

for (const item of items) {
  const response = item.json.response ?? [];

  for (const entry of response) {
    const p = entry.player;

    let agg = {
      matchesPlayed:  0,
      starts:         0,
      timePlayed:     0,
      duelsWon:       0,
      duelsLost:      0,
      goals:          0,
      goalAssists:    0,
      penaltyGoals:   0,
      totalPasses:    0,
      substituteOn:   0,
      substituteOff:  0,
      yellowCards:    0,
      yellowRedCards: 0,
      redCards:       0,
    };

    let position = null;
    let jerseyNumber = null;

    for (const stat of entry.statistics) {
      if (!ALLOWED_LEAGUES.has(stat.league?.id)) continue;

      const g      = stat.games       ?? {};
      const goals  = stat.goals       ?? {};
      const duels  = stat.duels       ?? {};
      const passes = stat.passes      ?? {};
      const cards  = stat.cards       ?? {};
      const subs   = stat.substitutes ?? {};
      const pen    = stat.penalty     ?? {};

      agg.matchesPlayed  += g.appearences   ?? 0;
      agg.starts         += g.lineups       ?? 0;
      agg.timePlayed     += g.minutes       ?? 0;
      agg.duelsWon       += duels.won       ?? 0;
      agg.duelsLost      += (duels.total ?? 0) - (duels.won ?? 0);
      agg.goals          += goals.total     ?? 0;
      agg.goalAssists    += goals.assists   ?? 0;
      agg.penaltyGoals   += pen.scored      ?? 0;
      agg.totalPasses    += passes.total    ?? 0;
      agg.substituteOn   += subs.in         ?? 0;
      agg.substituteOff  += subs.out        ?? 0;
      agg.yellowCards    += cards.yellow    ?? 0;
      agg.yellowRedCards += cards.yellowred ?? 0;
      agg.redCards       += cards.red       ?? 0;

      if (!position && g.position) position = g.position;
      if (!jerseyNumber && g.number) jerseyNumber = g.number;
    }

    results.push({
      json: {
        id:          p.id,
        sport:       "Football",
        firstName:   p.firstname,
        lastName:    p.lastname,
        shortName:   p.name ?? null,
        displayName: p.name ?? null,
        knownName:   null,
        birthday:    p.birth?.date ?? null,
        birthplace:  p.birth?.place ?? null,
        weight:      p.weight ? parseInt(p.weight) : null,
        height:      p.height ? parseInt(p.height) : null,
        jerseyNumber: jerseyNumber ?? null,
        country:     p.nationality ?? null,
        imageUrl:    p.photo ?? null,
        personHeroImageUrl: null,
        profile:     null,
        hidden:      false,
        position:    positionMap[position] ?? null,
        teamId:      entry.statistics[0]?.team?.id ?? null,
        joinedOn:    null,
        statistics: {
          sport:          "Football",
          matchesPlayed:  agg.matchesPlayed  || null,
          starts:         agg.starts         || null,
          timePlayed:     agg.timePlayed     || null,
          duelsWon:       agg.duelsWon       || null,
          duelsLost:      agg.duelsLost      || null,
          goals:          agg.goals          || null,
          goalAssists:    agg.goalAssists    || null,
          penaltyGoals:   agg.penaltyGoals   || null,
          totalPasses:    agg.totalPasses    || null,
          substituteOn:   agg.substituteOn   || null,
          substituteOff:  agg.substituteOff  || null,
          yellowCards:    agg.yellowCards    || null,
          yellowRedCards: agg.yellowRedCards || null,
          redCards:       agg.redCards       || null,
          rightFootGoals:                 null,
          leftFootGoals:                  null,
          goalsFromInsideBox:             null,
          goalsFromOutsideBox:            null,
          headedGoals:                    null,
          successfulLongPasses:           null,
          successfulShortPasses:          null,
          touches:                        null,
          successfulPassesOwnHalf:        null,
          successfulPassesOppositionHalf: null,
        }
      }
    });
  }
}

return results;

const item = $input.first();
console.error(`PATCH failed for player ${item.json.id ?? 'unknown'}: Status ${item.json.statusCode} – ${JSON.stringify(item.json.body ?? item.json)}`);
return [item];
